import{_ as t,c as l,o as i,a1 as e}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Часто задаваемые вопросы и оптимизация: устранение неполадок, команды CLI, настройка производительности | Учебник Clawdbot","description":"Решайте распространённые проблемы при использовании Clawdbot, осваивайте полную справку по командам CLI и изучайте методы оптимизации производительности для повышения стабильности системы и скорости ответа.","frontmatter":{"title":"Часто задаваемые вопросы и оптимизация: устранение неполадок, команды CLI, настройка производительности | Учебник Clawdbot","sidebarTitle":"Что делать при возникновении проблем","subtitle":"Часто задаваемые вопросы и оптимизация","description":"Решайте распространённые проблемы при использовании Clawdbot, осваивайте полную справку по командам CLI и изучайте методы оптимизации производительности для повышения стабильности системы и скорости ответа.","tags":["Часто задаваемые вопросы","Устранение неполадок","CLI","Оптимизация производительности"],"order":300},"headers":[],"relativePath":"ru/moltbot/moltbot/faq/index.md","filePath":"ru/moltbot/moltbot/faq/index.md"}'),o={name:"ru/moltbot/moltbot/faq/index.md"};function r(n,a,s,d,h,p){return i(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="часто-задаваемые-вопросы-и-оптимизация" tabindex="-1">Часто задаваемые вопросы и оптимизация <a class="header-anchor" href="#часто-задаваемые-вопросы-и-оптимизация" aria-label="Permalink to &quot;Часто задаваемые вопросы и оптимизация&quot;">​</a></h1><p>Эта глава помогает вам решать различные проблемы при использовании Clawdbot, осваивать полные методы работы с командной строкой и учиться оптимизировать производительность системы.</p><div class="info custom-block"><p class="custom-block-title">Рекомендация по порядку обучения</p><p>Рекомендуется читать эту главу в следующем порядке:</p><ol><li>Сначала изучите <strong><a href="./cli-commands/">Справка по командам CLI</a></strong> —— Освойте базовые операции и инструменты отладки</li><li>Затем изучите <strong><a href="./troubleshooting/">Устранение неполадок</a></strong> —— Чтобы быстро выявлять и решать проблемы при их возникновении</li><li>Наконец изучите <strong><a href="./performance-optimization/">Оптимизация производительности</a></strong> —— Чтобы повысить эффективность системы</li></ol></div><h2 id="навигация-по-подстраницам" tabindex="-1">Навигация по подстраницам <a class="header-anchor" href="#навигация-по-подстраницам" aria-label="Permalink to &quot;Навигация по подстраницам&quot;">​</a></h2><h3 id="устранение-неполадок" tabindex="-1"><a href="./troubleshooting/">Устранение неполадок</a> <a class="header-anchor" href="#устранение-неполадок" aria-label="Permalink to &quot;[Устранение неполадок](./troubleshooting/)&quot;">​</a></h3><p>Полное руководство по устранению неполадок для распространённых проблем, охватывающее:</p><ul><li>Сбои при запуске Gateway</li><li>Проблемы с подключением каналов (WhatsApp, Telegram, Slack и др.)</li><li>Ошибки аутентификации и проблемы с правами доступа</li><li>Сбои при вызове инструментов</li><li>Исключения при управлении сессиями</li></ul><p><strong>Когда использовать</strong>: Когда вы сталкиваетесь с конкретными проблемами и необходимо быстро устранить и решить их.</p><hr><h3 id="справка-по-командам-cli" tabindex="-1"><a href="./cli-commands/">Справка по командам CLI</a> <a class="header-anchor" href="#справка-по-командам-cli" aria-label="Permalink to &quot;[Справка по командам CLI](./cli-commands/)&quot;">​</a></h3><p>Полный список команд и инструкции по использованию, включая:</p><ul><li>Команды управления Gateway (запуск, перезапуск, статус)</li><li>Команды взаимодействия с Agent</li><li>Управление и настройка моделей</li><li>Управление каналами (вход, статус, выход)</li><li>Управление сессиями (список, сброс, удаление, сжатие)</li><li>Управление узлами (список, вызов, сопряжение)</li><li>Управление навыками и мастер настройки</li></ul><p><strong>Когда использовать</strong>: Когда вам нужно быстро найти использование и параметры команды, или изучить полную функциональность CLI.</p><hr><h3 id="оптимизация-производительности" tabindex="-1"><a href="./performance-optimization/">Оптимизация производительности</a> <a class="header-anchor" href="#оптимизация-производительности" aria-label="Permalink to &quot;[Оптимизация производительности](./performance-optimization/)&quot;">​</a></h3><p>Методы оптимизации для повышения производительности и скорости ответа Gateway, охватывающие:</p><ul><li>Кэширование промптов (Prompt Caching) для снижения затрат</li><li>Обрезка сессий (Session Pruning) для уменьшения контекста</li><li>Управление параллелизмом и управление ресурсами</li><li>Оптимизация памяти и сборка мусора</li><li>Настройка уровней журналирования</li></ul><p><strong>Когда использовать</strong>: Когда система работает медленно, использование ресурсов высоко, или вы хотите улучшить взаимодействие с пользователем.</p><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед изучением этой главы рекомендуется, чтобы вы завершили:</p><ul><li>✅ <strong><a href="./../../start/getting-started/">Быстрый старт</a></strong> —— Понимание базовых процессов установки и настройки</li><li>✅ <strong><a href="./../../start/gateway-startup/">Запуск Gateway</a></strong> —— Знание того, как запускать и управлять Gateway</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить обучение:</p><ul><li><strong><a href="./../../appendix/config-reference/">Полная справка по настройке</a></strong> —— Глубокое понимание подробных объяснений всех параметров настройки</li><li><strong><a href="./../../appendix/deployment/">Варианты развёртывания</a></strong> —— Изучение того, как развернуть Clawdbot на различных платформах</li><li><strong><a href="./../../appendix/development/">Руководство по разработке</a></strong> —— Понимание разработки плагинов и процесса внесения вклада</li></ul>',24)])])}const u=t(o,[["render",r]]);export{m as __pageData,u as default};
